/*! Minimal jQuery-like library for this portfolio
 * This is NOT full jQuery. It implements only the subset of the API
 * required by the portfolio site: basic selection, iteration, simple
 * chaining, a getJSON helper, and size measurements. It exposes a
 * global `$` function and assigns itself to `window.$`.
 */
(function (global) {
  'use strict';

  /**
   * Main $ function for selecting elements or wrapping existing ones.
   * Accepts CSS selectors, DOM nodes, arrays or NodeLists.
   *
   * @param {string|Node|Array|NodeList} selector
   * @returns {jQueryLiteObject}
   */
  function $(selector) {
    // If a function is passed, execute it when DOM is ready (jQuery-style ready)
    if (typeof selector === 'function') {
      if (document.readyState === 'complete' || document.readyState === 'interactive') {
        // DOM already ready; execute callback asynchronously to mimic jQuery
        setTimeout(selector, 0);
      } else {
        document.addEventListener('DOMContentLoaded', selector);
      }
      // Return a wrapper around document to support chaining if needed
      return $(document);
    }

    let elements = [];
    if (typeof selector === 'string') {
      elements = Array.prototype.slice.call(
        document.querySelectorAll(selector)
      );
    } else if (selector instanceof Node || selector === window || selector === document) {
      elements = [selector];
    } else if (selector instanceof NodeList || Array.isArray(selector)) {
      elements = Array.prototype.slice.call(selector);
    } else if (selector != null) {
      elements = [selector];
    }
    return new jQueryLiteObject(elements);
  }

  /**
   * Lightweight wrapper object around DOM elements to provide a minimal
   * jQuery-like API. Supports chaining where appropriate.
   *
   * @param {Array<Node>} elements
   */
  function jQueryLiteObject(elements) {
    this.elements = elements || [];
    this.length = this.elements.length;
    // Assign numeric indexes for array-style access (e.g., obj[0])
    for (var i = 0; i < this.length; i++) {
      this[i] = this.elements[i];
    }
  }

  /**
   * Attach an event listener to each element in the wrapped set.
   * This implements the subset of jQuery's `.on()` used in the
   * portfolio. Only the basic signature (eventType, handler) is
   * supported; namespaces and delegation are not implemented.
   *
   * @param {string} eventType - The event type to listen for (e.g., 'click').
   * @param {Function} handler - The callback to run when the event fires.
   * @returns {jQueryLiteObject}
   */
  jQueryLiteObject.prototype.on = function (eventType, handler) {
    this.elements.forEach(function (el) {
      if (el && typeof el.addEventListener === 'function') {
        el.addEventListener(eventType, handler);
      }
    });
    return this;
  };

  /**
   * Iterate over each element and execute callback. Mimics jQuery's each.
   *
   * @param {Function} callback - function(index, element)
   * @returns {jQueryLiteObject}
   */
  jQueryLiteObject.prototype.each = function (callback) {
    this.elements.forEach(function (el, idx) {
      callback.call(el, idx, el);
    });
    return this;
  };

  /**
   * Get direct children of the selected elements and wrap them.
   *
   * @returns {jQueryLiteObject}
   */
  jQueryLiteObject.prototype.children = function () {
    let children = [];
    this.elements.forEach(function (el) {
      children = children.concat(Array.prototype.slice.call(el.children));
    });
    return $(children);
  };

  /**
   * Retrieve an element by index and wrap it.
   *
   * @param {number} index
   * @returns {jQueryLiteObject}
   */
  jQueryLiteObject.prototype.eq = function (index) {
    if (index < 0) index = this.elements.length + index;
    const el = this.elements[index];
    return $(el);
  };

  /**
   * Return the outer width of the first element. If includeMargin is true,
   * margins are included.
   *
   * @param {boolean} includeMargin
   * @returns {number}
   */
  jQueryLiteObject.prototype.outerWidth = function (includeMargin) {
    if (!this.elements[0]) return 0;
    const el = this.elements[0];
    let width = el.getBoundingClientRect().width;
    if (includeMargin) {
      const style = getComputedStyle(el);
      width +=
        parseFloat(style.marginLeft || 0) + parseFloat(style.marginRight || 0);
    }
    return width;
  };

  /**
   * Add arbitrary data to the first element or retrieve it.
   *
   * @param {string} key
   * @param {*} [value]
   * @returns {*|jQueryLiteObject}
   */
  jQueryLiteObject.prototype.data = function (key, value) {
    if (!this.elements[0]) return value === undefined ? undefined : this;
    const el = this.elements[0];
    if (!el.__dataStore) el.__dataStore = {};
    if (value === undefined) {
      return el.__dataStore[key];
    } else {
      el.__dataStore[key] = value;
      return this;
    }
  };

  /**
   * Set or get the text content of the first element.
   *
   * @param {string} [value]
   * @returns {string|jQueryLiteObject}
   */
  jQueryLiteObject.prototype.text = function (value) {
    if (!this.elements[0]) return value === undefined ? '' : this;
    if (value === undefined) {
      return this.elements[0].textContent;
    } else {
      this.elements[0].textContent = value;
      return this;
    }
  };

  /**
   * jQuery-like AJAX helper for loading JSON files. Uses Fetch API.
   *
   * @param {string} url
   * @param {Function} successCallback
   */
  $.getJSON = function (url, successCallback) {
    fetch(url)
      .then(function (response) {
        if (!response.ok) {
          throw new Error('Network response was not ok');
        }
        return response.json();
      })
      .then(function (data) {
        if (typeof successCallback === 'function') successCallback(data);
      })
      .catch(function (error) {
        console.error('Error fetching JSON:', error);
      });
  };

  // Expose $ globally
  global.$ = $;
})(typeof window !== 'undefined' ? window : this);